mapper.select:
SELECT r.id, r.registration_no, r.patient_id, r.patient_name, r.phone, r.gender, r.age, r.department_name, r.doctor_id, r.doctor_name, r.visit_type, r.visit_time, r.status, r.registration_fee, r.diagnosis_fee, r.operator, r.remark, r.created_at, r.updated_at, r.deleted, c.order_no AS charge_order_no, c.receivable_amount, c.discount_amount, c.paid_amount, c.pay_method, c.paid_at, c.cashier FROM clinic_registration r LEFT JOIN clinic_charge_order c ON c.id = ( SELECT c2.id FROM clinic_charge_order c2 WHERE c2.deleted = 0 AND c2.registration_id = r.id ORDER BY c2.id DESC LIMIT 1 ) WHERE r.deleted = 0
AND (r.registration_no LIKE CONCAT('%', #{keyword}, '%') OR r.patient_name LIKE CONCAT('%', #{keyword}, '%') OR r.phone LIKE CONCAT('%', #{keyword}, '%') OR r.department_name LIKE CONCAT('%', #{keyword}, '%') OR r.doctor_name LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY r.id DESC LIMIT #{size} OFFSET #{offset}

mapper.update:
UPDATE clinic_registration
SET deleted = 1, updated_at = NOW()
WHERE id = #{id}
